export const CURSOR_RULE_RAW: Record<string, string> = {
  "bold-text-labels": "---\ndescription: Text field labels should be bold so they read clearly as labels\nglobs: \"**/*.{tsx,jsx}\"\nalwaysApply: false\n---\n\n# Bold text labels\n\nText labels that name a field (form labels, read-only field captions like **Schedule**, **Last run**, **Status**, dialog section labels) should be **bold** so they read clearly as labels rather than values.\n\n## Rule\n\nWhen rendering a label for a field or labeled value group, set `fontWeight` to **700** (or `bold`) in `sx`. Keep the value text at normal weight unless it has another role (e.g. emphasized title).\n\n```tsx\n// ❌ BAD — label and value weight look the same\n<Typography variant=\"caption\" color=\"text.secondary\">\n  Schedule\n</Typography>\n<Typography variant=\"body2\">{scheduleCode}</Typography>\n\n// ✅ GOOD\n<Typography variant=\"caption\" color=\"text.secondary\" sx={{ fontWeight: 700 }}>\n  Schedule\n</Typography>\n<Typography variant=\"body2\">{scheduleCode}</Typography>\n```\n\n## Applies to\n\n- Read-only field labels on admin/detail cards\n- Form field helper labels that act as the field name (when not using MUI `InputLabel` / `FormLabel`, which already convey hierarchy)\n- Section or dialog labels that identify the meaning of nearby content\n\n## Does not apply to\n\n- Body copy, descriptions, helper hints that are not field names\n- Button text, chip labels, navigation items\n- Page titles / headings (use heading variants instead)\n",
  "database-audit-columns": "---\ndescription: Standard row audit columns for database tables and SQL written by the agent\nglobs: database/**/*\nalwaysApply: false\n---\n\n# Database audit columns\n\nEvery `public` table uses these four columns:\n\n| Column | Type | Notes |\n|--------|------|--------|\n| `created_date` | `TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP` | Set on insert |\n| `created_by` | `varchar(128) NOT NULL` | Who created the row |\n| `modified_date` | `TIMESTAMPTZ NULL DEFAULT NULL` | Set on every update; **NULL on insert** |\n| `modified_by` | `varchar(128) NULL DEFAULT NULL` | Who last changed the row; **NULL on insert** |\n\nDo **not** use epoch placeholder defaults (`1970-01-01`, `1969-12-31`, etc.).\n\n## Cursor AI Agent (seeds / migrations)\n\n- **Insert:** `created_by = 'c-agent'`; leave `modified_by` and `modified_date` **NULL** (omit from column list or set explicitly to `NULL`).\n- **Seed UPDATE scripts:** do **not** set `modified_by` / `modified_date` (leave unchanged from insert).\n- **Agent UPDATE** (non-seed): `modified_by = 'c-agent'` and `modified_date = CURRENT_TIMESTAMP`.\n\n## Application / logged-in users\n\n- **Insert (self-registration):** `created_by = username`; `modified_by` / `modified_date` NULL.\n- **Update (RPC or REST PATCH):** `modified_by` = acting user's **username**; `modified_date = CURRENT_TIMESTAMP`.\n- RPCs call `api.set_audit_actor(username)` before `UPDATE`; migration `026_modified_audit_actor.sql` adds a `BEFORE UPDATE` trigger that applies the JWT username on REST PATCH when available.\n\n```sql\nINSERT INTO public.static_list (list_code, governing_body_code, short_desc, list_json)\nVALUES ('EXAMPLE_LIST', 'GLOBAL', 'Example lookup list', '[]'::json);\n\nUPDATE public.\"user\"\nSET email = lower(trim(p_email)),\n    modified_by = 'c-agent',\n    modified_date = CURRENT_TIMESTAMP\nWHERE user_id = v_user_id;\n```\n",
  "database-timestamp-format": "---\ndescription: Canonical readable timestamp format when saving datetime strings\nalwaysApply: true\n---\n\n# Readable datetime strings\n\nWhen saving a **datetime as a string** (JSON text fields, `additional_info_json`, activity strings, audit-style payloads), use:\n\n**Example:** `Jul 11, 2026, 5:42:28 AM CDT`\n\n- Abbreviated month (`Jul`), day, year, comma, 12-hour time **with seconds**, `AM`/`PM`, timezone abbreviation (`CDT`)\n- **No milliseconds**\n- **No ISO-8601** (e.g. `2026-07-11T05:42:28-05:00`)\n\nApplies to keys such as `last_login_at`, `last_logout_at`, `last-activity`, and any new string datetime fields (unless a field documents its own format, e.g. WSDC `last_update_datetime`).\n\n## PostgreSQL\n\nUse `api.format_activity_timestamp(date_trunc('second', p_ts))`. Parse with `api.parse_activity_timestamp(text)`.\n\n```sql\n-- ❌ BAD\njsonb_build_object('last_login_at', to_jsonb(v_now))\n\n-- ✅ GOOD\njsonb_build_object(\n  'last_login_at',\n  to_jsonb(api.format_activity_timestamp(date_trunc('second', v_now)))\n)\n```\n\n`TIMESTAMPTZ` columns (`created_date`, `modified_date`, …) stay as real timestamps — do not stringify those.\n\n## Frontend\n\nUse `formatReadableDateTime()` from `front-ends/front-end-cursor/src/utils/auditTimestamps.ts`.\n\n```ts\n// ❌ BAD\ninfo.last_login_at = new Date().toISOString();\n\n// ✅ GOOD\ninfo.last_login_at = formatReadableDateTime(new Date());\n```\n",
  "demo-attendee-id-reservation": "---\ndescription: Reserved attendee_id range for demo seed data and production attendee inserts\nalwaysApply: true\n---\n\n# Demo attendee ID reservation\n\n`public.attendee.attendee_id` values **1 through 10000** are reserved for **demo seed data** (50 demo events × 200 attendees for current_year and current_year - 1).\n\n## Rules\n\n- **Never** insert production or real-world attendee rows with `attendee_id <= 10000`.\n- Application code, migrations, and manual SQL must allocate new attendees **above** the reserved range (identity sequence is bumped after the demo seed runs).\n- Demo content in the reserved range may change on each seed run (events, users, dates); the **ID slots** stay fixed.\n\n## Demo seed (`database/seeds/012_attendee_seed.sql`)\n\n- **Safe to re-run** at any time (calls `api.generate_demo_attendees_core()`).\n- **Admin UI:** Admin home **Generate Attendees** button calls `api.generate_demo_attendees()` (requires admin JWT).\n- Deletes only `attendee_id <=` the reserved total, then inserts demo rows (`attendee_id` **1–10000** when all 50 recent-year demo events are present).\n- Does **not** truncate the table and does **not** delete rows above the reserved range.\n- After insert, resets the identity sequence to `GREATEST(reserved_max, MAX(attendee_id))` so the next production insert continues above real data.\n\n## Marking demo rows\n\n- `more_json->>'demo' = 'true'` (copied from the parent `event.more_json`)\n- `created_by = 'c-agent'` (seed convention; see `database-audit-columns` rule)\n\n## Example queries\n\n```sql\n-- Demo attendees only (reserved range)\nSELECT * FROM attendee WHERE attendee_id <= 10000;\n\n-- Production attendees only\nSELECT * FROM attendee WHERE attendee_id > 10000;\n\n-- Demo flag (any id)\nSELECT * FROM attendee WHERE (more_json->>'demo')::boolean = true;\n```\n\nWhen adding features that list or count attendees, treat the reserved range as demo unless explicitly filtering production data.\n",
  "mui-v9-sx-styling": "---\ndescription: MUI v9 — put layout and typography styles in sx, not legacy system props\nglobs: \"**/*.{tsx,jsx}\"\nalwaysApply: false\n---\n\n# MUI v9 styling (`sx` prop)\n\nThis project uses **@mui/material v9** with strict TypeScript types. Layout and typography **system props** on `Typography`, `Stack`, `Box`, etc. often cause **`TS2769: No overload matches`** and fail `tsc -b` in CI/Docker builds.\n\n## Rule\n\nWhen generating or editing MUI components, put **visual and flex layout styles in `sx`**, not as top-level props.\n\n**Still OK as direct props** (when the component supports them): `variant`, `color` (palette keys like `text.primary`), `direction`, `spacing`, `component`, `onClick`, `children`, `disabled`, etc.\n\n**Put in `sx`**: `fontWeight`, `fontSize`, `lineHeight`, `alignItems`, `justifyContent`, `flexWrap`, `gap` (when not `Stack spacing`), `width`, `height`, `padding`, `margin`, `display`, `minWidth`, `maxWidth`, and other CSS-like values.\n\n## Examples\n\n```tsx\n// BAD — breaks tsc on MUI v9\n<Typography variant=\"subtitle1\" fontWeight={700} color=\"text.primary\">\n<Stack direction=\"row\" alignItems=\"center\" spacing={1}>\n\n// GOOD\n<Typography variant=\"subtitle1\" color=\"text.primary\" sx={{ fontWeight: 700 }}>\n<Stack direction=\"row\" spacing={1} sx={{ alignItems: 'center' }}>\n```\n\nMerge with existing `sx`: `sx={{ width: '100%', alignItems: 'center', fontWeight: 700 }}`.\n\n## Before finishing UI changes\n\nRun `npm run build` in the front-end package (or ensure `tsc -b` passes) when touching MUI components.\n",
};
